import { Request, Response } from 'hono';
import Stripe from 'stripe';

const stripe = new Stripe('your_stripe_secret_key', {
  apiVersion: '2023-08-16',
});

export const handler = async (req: Request) => {
  const sigHeader = req.headers.get('Stripe-Signature');
  if (!sigHeader) {
    return new Response('Missing Stripe-Signature header', { status: 400 });
  }

  const payload = await req.text();
  let event;

  try {
    event = stripe.webhooks.constructEvent(
      payload,
      sigHeader,
      'your_webhook_secret'
    );
  } catch (err) {
    return new Response('Invalid signature', { status: 400 });
  }

  if (event.id && isIdempotent(event.id)) {
    return new Response('Duplicate event', { status: 200 });
  }

  switch (event.type) {
    case 'invoice.payment_succeeded':
      const invoice = event.data.object as Stripe.Invoice;
      await handleInvoicePaymentSucceeded(invoice);
      break;
    // Add more cases for other events you want to handle
    default:
      return new Response('Unhandled event type', { status: 200 });
  }

  return new Response('Event processed successfully', { status: 200 });
};

const isIdempotent = (eventId: string): boolean => {
  // Implement your idempotency logic here
  // For example, you can store the event ID in a database and check if it exists before processing
  return false;
};

const handleInvoicePaymentSucceeded = async (invoice: Stripe.Invoice) => {
  const subscriptionId = invoice.subscription as string;
  try {
    await stripe.subscriptions.update(subscriptionId, { proration_behavior: 'create_prorations' });
  } catch (err) {
    console.error('Error updating subscription:', err);
  }
};

